"""
    update_monitor(monitor_name)
    update_monitor(monitor_name, params::Dict{String,<:Any})

Update a monitor to add or remove local or remote resources.

# Arguments

- `monitor_name`: The name of the monitor.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"clientToken"`: A unique, case-sensitive string of up to 64 ASCII characters that you
  specify to make an idempotent API request. Don't reuse the same client token for other API
  requests.

- `"localResourcesToAdd"`: Additional local resources to specify network flows for a
  monitor, as an array of resources with identifiers and types. A local resource in a
  workload is the location of hosts where the Network Flow Monitor agent is installed.

- `"localResourcesToRemove"`: The local resources to remove, as an array of resources with
  identifiers and types.

- `"remoteResourcesToAdd"`: The remote resources to add, as an array of resources with
  identifiers and types.

  A remote resource is the other endpoint in the flow of a workload, with a local resource.
  For example, Amazon Dynamo DB can be a remote resource.

- `"remoteResourcesToRemove"`: The remote resources to remove, as an array of resources with
  identifiers and types.

  A remote resource is the other endpoint specified for the network flow of a workload, with
  a local resource. For example, Amazon Dynamo DB can be a remote resource.
"""
function update_monitor end

function update_monitor(monitorName; aws_config::AbstractAWSConfig=current_aws_config())
    return networkflowmonitor(
        "PATCH",
        "/monitors/$(monitorName)",
        Dict{String,Any}("clientToken" => string(uuid4()));
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function update_monitor(
    monitorName,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return networkflowmonitor(
        "PATCH",
        "/monitors/$(monitorName)",
        Dict{String,Any}(
            mergewith(_merge, Dict{String,Any}("clientToken" => string(uuid4())), params)
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

